SELECT
r.id, r.target_type, r.target_id, r.user_id, r.content, r.created_at, r.updated_at, t.title AS articleTitle
FROM reply r


        LEFT JOIN review t ON r.target_id = t.id


        LEFT JOIN post t ON r.target_id = t.id


WHERE r.target_type = #{targetType}
AND r.user_id = #{userId}
ORDER BY r.id DESC
LIMIT #{pageable.pageSize} OFFSET #{pageable.offset}

SELECT COUNT(id)
FROM reply
WHERE target_type = #{targetType}
AND user_id = #{userId}
